package main

import (
	"context"
	"encoding/json"
	"fmt"
	"os"

	"github.com/magicbell/magicbell-go/client"
	"github.com/magicbell/magicbell-go/clientconfig"
)

func main() {
	if len(os.Args) < 2 {
		fmt.Println("Usage: go run fetch_workflow.go <workflow_key>")
		os.Exit(1)
	}

	workflowKey := os.Args[1]
	projectToken := os.Getenv("MAGICBELL_PROJECT_TOKEN")

	cfg := clientconfig.NewConfig().WithProjectToken(projectToken)
	c := client.NewClient(cfg)

	ctx := context.Background()

	workflows, err := c.Workflows.FetchWorkflows(ctx)
	if err != nil {
		fmt.Printf("Error fetching workflows: %v\n", err)
		os.Exit(1)
	}

	if workflows.Workflows == nil {
		fmt.Println("Workflow not found")
		os.Exit(1)
	}

	for _, wf := range *workflows.Workflows {
		if wf.Key != nil && *wf.Key == workflowKey {
			b, err := json.MarshalIndent(wf, "", "  ")
			if err != nil {
				fmt.Printf("Error marshaling workflow: %v\n", err)
				os.Exit(1)
			}
			fmt.Println(string(b))
			os.Exit(0)
		}
	}

	fmt.Println("Workflow not found")
	os.Exit(1)
}

